// Find cases closed in the IRIS GUI whose SLA section is still pending,
// then build the filled-in description for each.
const fs = require('fs');
const SENT_CLOSED = '| 🔴 **Closed** | _pending — written on close_ |';
const SENT_TTR = '| **Time to resolve** | _pending_ |';
const SENT_STATUS = '| **Status** | ⏳ Open |';
const CLOSED_STATE_ID = 9;
const logPath = '/home/node/.n8n/workspace/siem-sla-metrics.jsonl';

const resp = $input.first().json;
const rows = resp.data || [];
const targets = rows.filter(c =>
  c.state_id === CLOSED_STATE_ID &&
  typeof c.case_description === 'string' &&
  c.case_description.includes(SENT_CLOSED));

const pad = n => String(n).padStart(2, '0');
const pretty = d => `${d.getUTCFullYear()}-${pad(d.getUTCMonth()+1)}-${pad(d.getUTCDate())} ${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:${pad(d.getUTCSeconds())}`;
const humanize = s => {
  if (s == null) return 'n/a';
  const h = Math.floor(s/3600), m = Math.floor((s%3600)/60), sec = s%60;
  const p = []; if (h) p.push(h+'h'); if (m) p.push(m+'m'); p.push(sec+'s'); return p.join(' ');
};

// Index sla_started events from the JSONL.
let started = {};
try {
  const lines = fs.readFileSync(logPath, 'utf8').trim().split('\n');
  for (const line of lines) {
    if (!line.trim()) continue;
    const e = JSON.parse(line);
    if (e.event === 'sla_started') started[String(e.case_id)] = e;
  }
} catch (e) {}

const now = new Date();
const reason = 'closed in IRIS console';
const out = [];

for (const c of targets) {
  const st = started[String(c.case_id)];
  const slaStart = st ? st.sla_start : null;
  const targetHours = st ? st.target_hours : null;
  const duration = slaStart ? Math.round((now.getTime() - new Date(slaStart).getTime())/1000) : null;

  let status_md;
  if (slaStart && targetHours != null && duration != null) {
    const t = targetHours * 3600;
    status_md = duration <= t
      ? `✅ **Met** (within ${targetHours}h) · ${reason}`
      : `❌ **Breached** (${targetHours}h target exceeded by ${humanize(duration - t)}) · ${reason}`;
  } else {
    status_md = `☑️ Closed · ${reason}`;
  }

  const desc = c.case_description
    .replace(SENT_CLOSED, `| 🔴 **Closed** | ${pretty(now)} UTC |`)
    .replace(SENT_TTR, `| **Time to resolve** | ${humanize(duration)} (${duration == null ? 'n/a' : duration + 's'}) |`)
    .replace(SENT_STATUS, `| **Status** | ${status_md} |`);

  out.push({ json: { case_id: c.case_id, case_description: desc } });

  try {
    fs.appendFileSync(logPath, JSON.stringify({
      case_id: c.case_id, sla_start: slaStart, sla_end: now.toISOString(),
      sla_duration_seconds: duration, target_hours: targetHours,
      event: 'sla_closed', via: 'gui_poller',
    }) + '\n');
  } catch (e) {}
}

return out;
